import{_ as e,a as t,b as i}from"./chunks/支持留言.NiGCLVdp.js";import{_ as s,o,c as l,a2 as p}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"블로그 사용 안내","description":"","frontmatter":{},"headers":[],"relativePath":"ko-KR/Other/blog.md","filePath":"ko-KR/Other/blog.md","lastUpdated":1781962217000}'),d={name:"ko-KR/Other/blog.md"};function n(c,a,r,h,g,b){return o(),l("div",null,[...a[0]||(a[0]=[p('<h1 id="블로그-사용-안내" tabindex="-1">블로그 사용 안내 <a class="header-anchor" href="#블로그-사용-안내" aria-label="Permalink to &quot;블로그 사용 안내&quot;">​</a></h1><p>블로그 기능을 켜면 ImgBed 사이트에 별도의 블로그 페이지를 추가할 수 있습니다.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://내도메인/blog/</span></span></code></pre></div><p><img src="'+e+'" alt="블로그 홈" loading="lazy"></p><p>이 블로그 페이지는 오픈소스 프로젝트 <a href="https://github.com/LyraVoid/Mizuki" target="_blank" rel="noreferrer">LyraVoid/Mizuki</a>를 바탕으로 ImgBed에 맞게 Vue로 다시 구성한 기능입니다.</p><h2 id="설정-위치" tabindex="-1">설정 위치 <a class="header-anchor" href="#설정-위치" aria-label="Permalink to &quot;설정 위치&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>시스템 설정 -&gt; 기타 설정 -&gt; 블로그</span></span></code></pre></div><p><img src="'+t+'" alt="블로그 설정" loading="lazy"></p><h2 id="처음-사용할-때" tabindex="-1">처음 사용할 때 <a class="header-anchor" href="#처음-사용할-때" aria-label="Permalink to &quot;처음 사용할 때&quot;">​</a></h2><ol><li><code>사용</code> 스위치를 켭니다.</li><li>블로그 설정을 저장할 GitHub 계정을 선택합니다.</li><li><code>블로그 업데이트</code>를 누릅니다.</li><li>업데이트 성공 안내가 나올 때까지 기다립니다.</li><li><code>https://내도메인/blog/</code> 주소로 접속해 확인합니다.</li></ol><p>처음 사용할 때는 선택한 GitHub 계정 아래에 비공개 저장소가 준비됩니다.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imgbed-blog-config</span></span></code></pre></div><p>이 저장소에는 블로그 설정과 글 내용이 저장됩니다.</p><h2 id="글-작성-방식" tabindex="-1">글 작성 방식 <a class="header-anchor" href="#글-작성-방식" aria-label="Permalink to &quot;글 작성 방식&quot;">​</a></h2><p>블로그 글은 본인의 GitHub 비공개 저장소 <code>imgbed-blog-config</code>에서 수정합니다.</p><p>일반적인 작업 흐름은 다음과 같습니다.</p><ol><li>GitHub를 엽니다.</li><li><code>imgbed-blog-config</code> 저장소로 들어갑니다.</li><li>글 파일을 새로 만들거나 수정합니다.</li><li>변경 내용을 커밋합니다.</li><li>ImgBed 관리자 화면으로 돌아와 <code>블로그 업데이트</code>를 누릅니다. 블로그 홈 왼쪽 위 로고를 세 번 눌러 업데이트를 트리거할 수도 있습니다.</li></ol><p><code>블로그 업데이트</code>는 이미 작성한 글을 덮어쓰는 기능이 아닙니다. 저장소를 처음 준비하거나 블로그 캐시를 새로고침할 때 사용합니다.</p><h2 id="지원-기능" tabindex="-1">지원 기능 <a class="header-anchor" href="#지원-기능" aria-label="Permalink to &quot;지원 기능&quot;">​</a></h2><p>글 목록, 카테고리, 태그, 아카이브, 검색, 다크 모드, 다국어 전환 같은 기본 블로그 기능을 지원합니다.</p><p>댓글과 방문 통계도 사용할 수 있습니다.</p><p><img src="'+i+'" alt="블로그 댓글" loading="lazy"></p><p>댓글은 글 아래에 표시됩니다. 방문자는 아바타, 닉네임, 이메일, 댓글 내용을 입력해 남길 수 있습니다.</p><p>방문 통계에서는 글 조회수와 사이트 방문 수를 확인할 수 있어 블로그 이용 현황을 파악하기 좋습니다.</p><h2 id="접속-주소" tabindex="-1">접속 주소 <a class="header-anchor" href="#접속-주소" aria-label="Permalink to &quot;접속 주소&quot;">​</a></h2><p>블로그는 항상 <code>/blog/</code> 경로에서 열립니다.</p><p>예를 들어 ImgBed 도메인이 다음과 같다면:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://image.example.com</span></span></code></pre></div><p>블로그 주소는 다음과 같습니다.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://image.example.com/blog/</span></span></code></pre></div><p>블로그를 끄면 방문자는 블로그 페이지에 접속할 수 없습니다.</p>',31)])])}const _=s(d,[["render",n]]);export{k as __pageData,_ as default};
